      8217, // ' ""curly apostrophe"" or "right single quotation mark" (CP-1252: 146)

      //  8220, // " Left double quotation mark (CP-1252: 147)
      //  8221, // " Right double quotation mark (CP-1252: 148)
      8226, // • Bullet (CP-1252: 149)

